  ('heelevel3-7c4986e7-moex-00076', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'essay', '下列之交易事項皆為各自獨立，試分別回答其問題：
（每小題 5分，共 25 分）
甲公司會計年度截止日為12月31日。甲公司給與其24位員工每人每
年 15 天的可累積帶薪休假，員工平均日薪為$3,500，甲公司預估會有
90%之休假在當年度被行使，截至X1年3月31日止共有60天之休假
實際發生，則該公司於X1年第一季資產負債表，應認列多少負債？
乙公司於 X1年初以$1,000,000 購買土地種植梨樹，且於 X1 年間因種
植梨樹而支出$200,000，X1年底產出公允價值為$300,000 的水梨。若
乙公司將水梨運至市場出售尚需支付銷售成本$40,000，則乙公司於
X1 年資產負債表上應列示農產品之金額為何？
丙公司銷售機器設備提供零件保固，若每個零件更換成本均為$1,500。
公司依照過去經驗估計，有 25%會發生一個零件故障，20%會發生二
個零件故障，10%會發生三個零件故障，則每售出一台機器設備應認
列多少負債？
丁公司於 X1 年 7 月 1 日以 A 設備（成本$400,000，已提列累計折舊
$180,000，公允價值為$210,000）來交換戊公司的 B 設備（成本
$500,000，已提列累計折舊$300,000，公允價值為$210,000）。該交換交
易具商業實質，則丁公司應認列多少處分資產損失或利益？
己公司於 X1 年初以總成本$300,000 購入機器設備一台，預計使用 5
年，殘值為$30,000，採用年數合計法提列折舊。X2 年初對該機器設
備投入改良性資本支出$150,000，該支出並使機器之使用年限多延長
1 年，但殘值減少為$20,000。己公司同時決定自 X2 年起改採用直線
法提列折舊，則X2 年底己公司應提列多少折舊費用？', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00077', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '某公司製造的甲產品需使用A原料，使用A原料尚須投入加工成本$1,800,000才能完工，完工後 製成品甲的生產成本為$3,000,000，估計售價為$3,120,000，估計銷售費用為$360,000。庫存原料 A的期末帳面金額為$1,200,000，但期末由市場買入的價格已降至$960,000。下列敘述何者正確？', '["因甲產品的估計售價仍高於製成品的生產成本，故原料A毋須認列跌價損失", "原料A的淨變現價值為$1,320,000，高於其帳面價值$1,200,000，故原料A毋須認列跌價損失", "原料 A 的淨變現價值為$960,000，低於其帳面價值$1,200,000，故原料 A 須認列跌價損失 $240,000", "原料A的淨變現價值為$1,320,000，高於其重置成本$960,000，故原料A毋須認列跌價損失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00078', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '某公司X7年度的稅後淨利為$140,000，且利息費用為$40,000，若公司之所得稅率為30%，則X7 年度之利息保障倍數為：', '["3.5", "4.5", "5", "6 31940"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00079', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '某公司由其客戶收到一張面額$30,000，6個月期、利率10%之票據，在收到票據2個月後持此票 據向銀行貼現，貼現息為12%，請問該公司可以由銀行收到多少現金？', '["$31,500", "$30,300", "$30,280", "$30,240"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00080', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司收到銀行對帳單餘額為$31,210，公司帳列餘額為$30,270，另發現銀行代收票據$9,100，代 扣手續費$620，而公司流通在外支票仍有$7,600尚未兌現，請問在途存款金額為何？', '["$15,140", "$15,760", "$8,160", "$16,380"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00081', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '某公司 2023 年度原列報之淨利為$95,000，2024 年初發現 2022 年及 2023 年底之存貨分別低估 $12,500及$20,500，請問2023年度正確之淨利應為：', '["$63,000", "$75,000", "$87,000", "$103,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00082', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司 X1 年度之預期信用減損損失為$250,000，出售土地利益$456,000，廠房徵收之利益為 $380,000，稅率20%，應付所得稅減少$72,000，本期淨利$2,000,000。請問甲公司X1年度營業活 動之淨現金流量為何？', '["$1,581,000", "$1,486,000", "$1,437,000", "$1,342,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00083', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X3年初取得乙公司25%之股權，取得時投資成本與被投資公司股權淨值間無差異，甲 公司對此項投資以權益法處理，且甲公司只有此項股權投資交易。X3年底甲公司採權益法之投資 科目餘額為$250,000，假設乙公司X3年度之淨利為$150,000，宣告並支付股利$60,000，請問甲公 司X3年初取得此投資之成本為：', '["$207,500", "$217,500", "$227,500", "$255,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00084', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列為甲公司證券投資之明細資料 公允價值 成本 X5年底 X6年底 透過損益按公允價值衡量之金融資產 $300,000 $200,000 $310,000 按攤銷後成本衡量之金融資產 300,000 220,000 240,000 請問甲公司X6年綜合損益表之損益項目中金融資產評價利益為何？', '["$100,000", "$110,000", "$120,000", "$130,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
